code = """import json
import re
from collections import defaultdict

# Load patent data
data_file = locals()['var_functions.query_db:12']
with open(data_file, 'r') as f:
    all_records = json.load(f)

print('Total records: ' + str(len(all_records)))

# Find DE pattern samples first
samples_de = []
for i in range(min(10000, len(all_records))):
    record = all_records[i]
    patents_info = record.get('Patents_info', '')
    if 'DE-' in patents_info or 'Germany' in patents_info or 'from DE' in patents_info:
        grant_date = record.get('grant_date', '')
        year_match = re.search(r'\b(2019)\b', grant_date)
        if year_match:
            samples_de.append({
                'idx': i,
                'patents_info': patents_info,
                'grant_date': grant_date
            })
            if len(samples_de) >= 5:
                break

print('Found ' + str(len(samples_de)) + ' potential German 2019 patents in first 10k')
for sample in samples_de:
    print('Index ' + str(sample['idx']) + ': ' + sample['grant_date'] + ' - ' + sample['patents_info'][:80])

# Now process all records properly
german_patents = []
cpc_history = defaultdict(lambda: defaultdict(int))
cpc_2019_h2 = defaultdict(int)

month_map = {'january':1,'february':2,'march':3,'april':4,'may':5,'june':6,
             'july':7,'august':8,'september':9,'october':10,'november':11,'december':12}

for record in all_records:
    patents_info = record.get('Patents_info', '')
    grant_date = record.get('grant_date', '')
    cpc_str = record.get('cpc', '')
    
    if not patents_info or not grant_date:
        continue
    
    # Check German patterns
    info_lower = patents_info.lower()
    if not ('de-' in info_lower or 'germany' in info_lower or 'from de' in info_lower or patents_info.startswith('DE ')):
        continue
    
    # Parse year
    year_match = re.search(r'\b(201\d|202[0-4])\b', grant_date)
    if not year_match:
        continue
    year = int(year_match.group(1))
    if year < 2015 or year > 2024:
        continue
    
    # Parse month
    month_num = 0
    for month_name in month_map:
        if month_name in grant_date.lower():
            month_num = month_map[month_name]
            break
    if month_num == 0:
        continue
    
    is_h2_2019 = (year == 2019 and month_num >= 7)
    
    # Parse CPC
    if not cpc_str:
        continue
    try:
        cpc_codes_raw = json.loads(cpc_str.strip())
        cpc_codes = []
        for item in cpc_codes_raw:
            if isinstance(item, dict) and item.get('code'):
                cpc_codes.append(item['code'])
    except:
        continue
    
    german_patents.append({
        'patents_info': patents_info,
        'grant_date': grant_date,
        'year': year,
        'is_h2_2019': is_h2_2019,
        'cpc_codes': cpc_codes
    })
    
    for code in cpc_codes:
        mg = code.strip().split('/')[0]
        if len(mg) >= 5:
            cpc_history[mg][year] += 1
            if is_h2_2019:
                cpc_2019_h2[mg] += 1

print('Processed ' + str(len(german_patents)) + ' German patents')
print('CPC codes with H2 2019 data: ' + str(len(cpc_2019_h2)))

# Calculate EMA for top CPC codes
top_cpc_codes = sorted(cpc_2019_h2.items(), key=lambda x: x[1], reverse=True)[:30]
print('\nTop 15 CPC codes by H2 2019 filings:')
for i in range(min(15, len(top_cpc_codes))):
    code, count = top_cpc_codes[i]
    print(str(i+1) + '. ' + code + ': ' + str(count))

def calc_ema(values, alpha=0.1):
    if not values:
        return {}
    sorted_vals = sorted(values.items())
    ema_vals = {}
    ema = None
    for year, val in sorted_vals:
        if ema is None:
            ema = float(val)
        else:
            ema = alpha * val + (1-alpha) * ema
        ema_vals[year] = round(ema, 2)
    return ema_vals

# Get full results for top codes
top_results = []
for code, filings_2019 in top_cpc_codes:
    year_data = dict(cpc_history[code])
    ema_data = calc_ema(year_data)
    if ema_data:
        max_ema = max(ema_data.items(), key=lambda x: x[1])
        top_results.append({
            'cpc_code': code,
            'best_year': max_ema[0],
            'best_ema': max_ema[1],
            'filings_2019': filings_2019,
            'history': year_data,
            'ema_values': ema_data
        })

top_results.sort(key=lambda x: x['best_ema'], reverse=True)

print('\nTop 10 by highest EMA:')
for i in range(min(10, len(top_results))):
    r = top_results[i]
    print(str(i+1) + '. ' + r['cpc_code'] + ' - Year: ' + str(r['best_year']) + ' (EMA: ' + str(round(r['best_ema'],2)) + '), 2019 filings: ' + str(r['filings_2019']))

cpc_for_lookup = [r['cpc_code'] for r in top_results[:20]]

print('__RESULT__:')
result_dict = {
    'german_patents': len(german_patents),
    'cpc_codes': cpc_for_lookup,
    'top_results': top_results[:20]
}
print(json.dumps(result_dict))"""

